    orders = pgTable("orders", {
      id: serial("id").primaryKey(),
      propertyId: integer("property_id"),
      roomId: integer("room_id"),
      bookingId: integer("booking_id"),
      guestId: integer("guest_id"),
      items: jsonb("items").notNull(),
      totalAmount: decimal("total_amount", { precision: 10, scale: 2 }).notNull(),
      status: varchar("status", { length: 20 }).notNull().default("new"),
      specialInstructions: text("special_instructions"),
      createdAt: timestamp("created_at").defaultNow(),
      updatedAt: timestamp("updated_at").defaultNow(),
      orderSource: varchar("order_source", { length: 50 }).notNull(),
      orderType: varchar("order_type", { length: 50 }),
      customerName: varchar("customer_name", { length: 255 }),
      customerPhone: varchar("customer_phone", { length: 20 }),
      paymentStatus: varchar("payment_status", { length: 20 }).default("unpaid"),
      paymentMethod: varchar("payment_method", { length: 20 }),
      // Dine-in table identifier (e.g. "T1", "A5"). Set for restaurant orders
      // placed via the table QR. Standalone — independent of hotel rooms.
      tableNumber: varchar("table_number", { length: 50 }),
      // 'dine-in' | 'takeaway' | 'room'. For restaurant orders this distinguishes
      // a guest seated at a table from a parcel/walk-in pickup. Defaults to
      // 'dine-in' for restaurant rows and 'room' for room-service rows.
      orderMode: varchar("order_mode", { length: 20 }).default("dine-in"),
      // Test Order Mode flag — when true, the order is excluded from ALL
      // financial calculations (revenue, P&L, wallet, reports). Used only
      // for kitchen/notification testing. Never set this on real orders.
      isTest: boolean("is_test").default(false).notNull(),
      // Second-level kitchen-acceptance escalation: stamped when the
      // background job has fired the "kitchen has not accepted this order
      // within X minutes" warning. NULL = not yet alerted. We never re-fire
      // for the same order (avoids alert spam). Cleared by status moves
      // implicitly because the job filters status='pending' only.
      acceptanceAlertSentAt: timestamp("acceptance_alert_sent_at")
    });
    insertOrderSchema = createInsertSchema(orders).omit({
      id: true,
      createdAt: true,
      updatedAt: true
    });
