      async getActivityLogs(filters) {
        const conditions = [];
        if (filters?.userId) {
          conditions.push(eq(activityLogs.userId, filters.userId));
        }
        if (filters?.category) {
          conditions.push(eq(activityLogs.category, filters.category));
        }
        if (filters?.propertyId) {
          conditions.push(eq(activityLogs.propertyId, filters.propertyId));
        }
        if (filters?.startDate) {
          conditions.push(gte(activityLogs.createdAt, filters.startDate));
        }
        if (filters?.endDate) {
          conditions.push(lte(activityLogs.createdAt, filters.endDate));
        }
        const whereClause = conditions.length > 0 ? and(...conditions) : void 0;
        const [countResult] = await db.select({ count: sql2`count(*)::int` }).from(activityLogs).where(whereClause);
        const total = countResult?.count || 0;
        let query = db.select().from(activityLogs).where(whereClause).orderBy(desc(activityLogs.createdAt));
        if (filters?.limit) {
          query = query.limit(filters.limit);
        }
        if (filters?.offset) {
          query = query.offset(filters.offset);
        }
        const logs = await query;
        return { logs, total };
      }
