      const cleanedType = (row.hostezee_room_type || "").replace(/[`'"]+$/g, "").trim();
      const roomsResult = await client.query(
        `SELECT DISTINCT room_type FROM rooms WHERE property_id = $1 AND room_type IS NOT NULL`,
        [row.property_id]
      );
